refsection.programlisting:
// Create a Box Benkhen deisgn with 3 variables
// and one repetition of the center point.
H = scidoe_bbdesign(3)
//
// Create a Box Benkhen design with 5 variables,
// and 3 repetitions of the center.
H = scidoe_bbdesign(5,3)
//
// Create a Box Benkhen design and visualise
// the result, using scidoe_plot_cube.sci
H = scidoe_bbdesign(3);
h = scf();
param3d(H(:,1),H(:,2),H(:,3))
h.children.children.mark_mode="on";
h.children.children.line_mode="off";
h.children.children.mark_size=1;
scidoe_plotcube(3)
